  ('aboriginal-444ca548-moex-00142', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-112-3082b5f1', 'sub-aboriginal-444ca548-01', NULL, 'single_choice', '關於多階段行政處分之敘述，下列何者錯誤？', '["須經其他機關協力始能作成行政處分", "先前階段之行為屬內部行為", "為上級機關對下級機關之監督", "最後階段之行為係行政處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:53+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "510", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
